def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 50.0 + np.log1p(cap) * 25
        fluctuation = 0.0
        if usage > 4:
            base_priority += 5000 * np.power(usage, 1.1)
            if cap > 10:
                base_priority += 100 * np.cbrt(cap) + 35 * np.cos(cap * 1.5)
            else:
                base_priority -= 40 * usage
            for i in range(1, 5):
                fluctuation += ((-1) ** (i+1)) * np.sin(usage * np.pi * i * 0.8) * 20 / i
        elif 3 < usage <= 4:
            delta = usage - 3
            base_priority += 1800 * delta ** 1.8 + 200 * (1 - delta ** 0.5)
            for j in range(1, 8):
                fluctuation += np.cos(usage * np.pi * (j ** 1.3)) * 25 / j
            if int(cap * 3) % 3 == 0:
                base_priority += 40 * np.tan(cap / 15)
        elif 2 < usage <= 3:
            base_priority += 1200 * (usage - 2)**2
            for k in range(1, 12):
                val = usage ** k
                if val < 0.4:
                    fluctuation += val * 10 / k
                    if k % 5 == 0:
                        fluctuation += 4 * k
                else:
                    fluctuation += (1 - val) * 18 / (k + 2)
                    if k == 9 and usage > 2.5:
                        fluctuation += 20
            if cap % 2.3 < 0.5:
                base_priority += 35 * np.sin(cap * 3)
        elif 1 < usage <= 2:
            base_priority += 900 * (usage - 1) ** 3
            for m in range(1, 15):
                pwr = usage ** m
                if pwr < 0.6:
                    fluctuation += pwr * 25 / m
                    if m % 3 == 1:
                        fluctuation -= 2 * m
                else:
                    fluctuation += (1 - pwr) * 12 / (m + 1)
                    if m == 12 and usage > 1.7:
                        fluctuation += 15
            if cap % 1.5 < 0.3:
                base_priority += 28 * np.cos(cap * 2)
        elif 0.5 < usage <= 1:
            base_priority += 130 * (1 - usage)
            for n in range(1, 11):
                pwr = usage ** n
                fluctuation += (np.tanh(pwr * np.pi / 4) - 0.3) * 12 / n
                if usage < 0.07 * n:
                    fluctuation -= 8 * n
            if cap < 0.15:
                base_priority += np.sqrt(cap) * 280
            elif cap < 0.85:
                base_priority += np.log1p(cap * 20) * 35
            else:
                base_priority += (cap % 5) * 22
        else:
            base_priority += 280 * (1 - usage) ** 2
            for o in range(1, 18):
                pwr = usage ** o
                fluctuation += (np.sin(pwr * np.pi / 6) - 0.25) * 13 / o
                if usage < 0.015 * o:
                    fluctuation -= 12 * o
            if cap < 0.015:
                base_priority += np.sqrt(cap) * 320
            elif cap < 0.9:
                base_priority += np.log1p(cap * 25) * 45
            else:
                base_priority += (cap % 6) * 30
        priority = base_priority + fluctuation
        if cap < 0.04:
            priority += 75
            if usage > 0.75:
                priority += 90
            elif usage < 0.12:
                priority -= 50
                for r in range(1, 7):
                    priority -= r * np.exp(-usage * 20)
        elif cap < 0.9:
            priority += 40
            if usage > 0.85:
                priority += 60
            elif usage < 0.2:
                priority -= 30
            for s in range(1, 6):
                if int(cap * 1200) % (s + 4) == 0:
                    priority += s * 7
                else:
                    priority -= s * 3
        else:
            if usage < 0.12:
                priority -= 40
                for t in range(1, 7):
                    priority -= t * 5
            elif usage > 0.92:
                priority += 90
                for u in range(1, 5):
                    priority += u * 10
            else:
                priority += 30
        proximity = 0
        if int(cap * 2500) % 19 == 0:
            proximity += 15
        if int(cap * 900) % 23 == 0:
            proximity -= 11
        if int(cap * 180) % 9 == 0:
            proximity += 13
        for w in range(1, 9):
            diff = abs(usage - w / 9)
            if diff < 0.02:
                proximity += 20 / w
            elif diff < 0.05:
                proximity += 11 / w
            else:
                proximity -= 4 / w
        for x in range(1, 8):
            mod_chk = int(cap * 1600) % (x + 9)
            if mod_chk == 0:
                proximity += x * 5
            elif mod_chk == 3:
                proximity -= x * 4
        for y in range(1, 5):
            mod_chk = int(usage * 1600) % (y + 6)
            if mod_chk == 0:
                proximity += 10 * y
            elif mod_chk == 3:
                proximity -= 7 * y
        priority += proximity
        if usage < 0.005:
            for z in range(1, 8):
                priority -= z * 10
        elif usage > 0.95:
            for aa in range(1, 7):
                priority += aa * 11
        if cap > 2.0:
            if cap % 1 < 0.06:
                priority += 40
            if (int(cap * 2500) % 23 == 0) and (usage > 0.7):
                priority += 60
            for bb in range(1, 6):
                if (int(cap * 600) % (bb + 9) == 2) and (usage < 0.85):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 2e4
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        priorities[idx] = priority
    return priorities
